/**
 * Which map holds each chapter quest. Order = story flow: map 01, then 02, ...
 * Positions for quest markers come from each map's interactive[] (generated by scripts/generate-maps.js).
 * Used to instruct player "Travel to [Map Name] to get your next quest" when the next chapter is on another map.
 * Chapters 1–100 are assigned round-robin across 18 maps (default, terrant, forest, desert, mountains, swamp, magical, mixed, + 10 extra).
 */
const MAP_IDS_ROUND_ROBIN = [
  'default', 'terrant', 'forest', 'desert', 'mountains', 'swamp', 'magical', 'mixed',
  'highland-vale', 'ember-wastes', 'whisper-woods', 'crimson-bog', 'sky-prairie', 'veil-garden',
  'frost-hollow', 'sand-shrine', 'thorn-marsh', 'eldritch-grove',
];

import { CHAPTER_QUESTS } from './chapter-quests.js';

export const CHAPTER_QUEST_MAPS = CHAPTER_QUESTS.map((q, i) => ({
  mapId: MAP_IDS_ROUND_ROBIN[i % MAP_IDS_ROUND_ROBIN.length],
  chapterQuestId: q.id,
}));

/**
 * Get the map id that holds a given chapter quest.
 * @param {string} chapterQuestId
 * @returns {string|undefined}
 */
export function getMapIdForChapterQuest(chapterQuestId) {
  const entry = CHAPTER_QUEST_MAPS.find((e) => e.chapterQuestId === chapterQuestId);
  return entry?.mapId;
}

/**
 * Get the next story map id (for "go to map 02" instruction) after the given chapter quest id.
 * @param {string} completedChapterQuestId
 * @param {import('./chapter-quests.js').ChapterQuest[]} chapterQuests - CHAPTER_QUESTS
 * @returns {{ mapId: string, mapName?: string }|null}
 */
export function getNextStoryMapAfter(completedChapterQuestId, chapterQuests) {
  const idx = CHAPTER_QUEST_MAPS.findIndex((e) => e.chapterQuestId === completedChapterQuestId);
  if (idx < 0 || idx >= CHAPTER_QUEST_MAPS.length - 1) return null;
  const next = CHAPTER_QUEST_MAPS[idx + 1];
  const nextQuest = chapterQuests.find((q) => q.id === next.chapterQuestId);
  return { mapId: next.mapId, mapName: nextQuest?.area ?? next.mapId };
}
